const execution = $input.item.json.execution;
const workflow = $input.item.json.workflow;

const logPayload = {
  timestamp: new Date().toISOString(),
  level: "error",
  service: "n8n",
  workflow: {
    id: workflow.id,
    name: workflow.name
  },
  execution: {
    id: execution.id,
    url: execution.url,
    failedNode: execution.lastNodeExecuted,
    error: {
      message: execution.error?.message || "Unknown error",
      stack: execution.error?.stack
    }
  }
};

// Print to container stdout (Vector will automatically ship this to Axiom)
console.log(JSON.stringify(logPayload));

return { json: logPayload };
